import{_ as a,c as i,o as n,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Funciones Avanzadas: Gestión de Múltiples Cuentas | Antigravity Auth","description":"Domina las características avanzadas del plugin Antigravity Auth. Aprende en profundidad los mecanismos principales como balanceo de carga entre cuentas, selección inteligente de cuentas, manejo de límites de velocidad, recuperación de sesiones y transformación de solicitudes.","frontmatter":{"title":"Funciones Avanzadas: Gestión de Múltiples Cuentas | Antigravity Auth","sidebarTitle":"Gestión de Múltiples Cuentas","subtitle":"Funciones Avanzadas: Gestión de Múltiples Cuentas","description":"Domina las características avanzadas del plugin Antigravity Auth. Aprende en profundidad los mecanismos principales como balanceo de carga entre cuentas, selección inteligente de cuentas, manejo de límites de velocidad, recuperación de sesiones y transformación de solicitudes.","order":3},"headers":[],"relativePath":"es/NoeFabris/opencode-antigravity-auth/advanced/index.md","filePath":"es/NoeFabris/opencode-antigravity-auth/advanced/index.md"}'),r={name:"es/NoeFabris/opencode-antigravity-auth/advanced/index.md"};function t(o,e,l,d,c,u){return n(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="funciones-avanzadas" tabindex="-1">Funciones Avanzadas <a class="header-anchor" href="#funciones-avanzadas" aria-label="Permalink to &quot;Funciones Avanzadas&quot;">​</a></h1><p>Esta sección te ayuda a dominar las características avanzadas del plugin Antigravity Auth, incluyendo balanceo de carga entre múltiples cuentas, selección inteligente de cuentas, manejo de límites de velocidad, recuperación de sesiones, transformación de solicitudes y otros mecanismos principales. Ya sea para optimizar el uso de cuotas o para resolver problemas complejos, aquí encontrarás las respuestas que necesitas.</p><h2 id="prerrequisitos" tabindex="-1">Prerrequisitos <a class="header-anchor" href="#prerrequisitos" aria-label="Permalink to &quot;Prerrequisitos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Antes de comenzar asegúrate de</p><ul><li>✅ Haber completado la <a href="./../../start/quick-install/">Instalación Rápida</a> y haber añadido la primera cuenta correctamente</li><li>✅ Haber completado la <a href="./../../start/first-auth-login/">Primera Autenticación</a> y comprender el flujo OAuth</li><li>✅ Haber completado la <a href="./../../start/first-request/">Primera Solicitud</a> y verificar que el plugin funciona correctamente</li></ul></div><h2 id="ruta-de-aprendizaje" tabindex="-1">Ruta de Aprendizaje <a class="header-anchor" href="#ruta-de-aprendizaje" aria-label="Permalink to &quot;Ruta de Aprendizaje&quot;">​</a></h2><h3 id="_1-configuracion-de-multiples-cuentas" tabindex="-1">1. <a href="./multi-account-setup/">Configuración de Múltiples Cuentas</a> <a class="header-anchor" href="#_1-configuracion-de-multiples-cuentas" aria-label="Permalink to &quot;1. [Configuración de Múltiples Cuentas](./multi-account-setup/)&quot;">​</a></h3><p>Configura múltiples cuentas de Google para implementar agrupación de cuotas y balanceo de carga.</p><ul><li>Añade múltiples cuentas para aumentar el límite total de cuotas</li><li>Comprende el sistema de cuotas dual (Antigravity + Gemini CLI)</li><li>Selecciona la cantidad adecuada de cuentas según el escenario</li></ul><h3 id="_2-estrategias-de-seleccion-de-cuentas" tabindex="-1">2. <a href="./account-selection-strategies/">Estrategias de Selección de Cuentas</a> <a class="header-anchor" href="#_2-estrategias-de-seleccion-de-cuentas" aria-label="Permalink to &quot;2. [Estrategias de Selección de Cuentas](./account-selection-strategies/)&quot;">​</a></h3><p>Domina las mejores prácticas de las tres estrategias de selección de cuentas: sticky, round-robin e híbrida.</p><ul><li>1 cuenta → Estrategia sticky para retener el caché de prompts</li><li>2-3 cuentas → Estrategia híbrida para distribución inteligente de solicitudes</li><li>4+ cuentas → Estrategia round-robin para maximizar el rendimiento</li></ul><h3 id="_3-manejo-de-limites-de-velocidad" tabindex="-1">3. <a href="./rate-limit-handling/">Manejo de Límites de Velocidad</a> <a class="header-anchor" href="#_3-manejo-de-limites-de-velocidad" aria-label="Permalink to &quot;3. [Manejo de Límites de Velocidad](./rate-limit-handling/)&quot;">​</a></h3><p>Comprende la detección de límites de velocidad, reintentos automáticos y mecanismos de cambio de cuenta.</p><ul><li>Distingue entre 5 tipos diferentes de errores 429</li><li>Comprende el algoritmo de retroceso exponencial para reintentos automáticos</li><li>Domina la lógica de cambio automático de cuentas en escenarios de múltiples cuentas</li></ul><h3 id="_4-recuperacion-de-sesiones" tabindex="-1">4. <a href="./session-recovery/">Recuperación de Sesiones</a> <a class="header-anchor" href="#_4-recuperacion-de-sesiones" aria-label="Permalink to &quot;4. [Recuperación de Sesiones](./session-recovery/)&quot;">​</a></h3><p>Conoce el mecanismo de recuperación de sesiones que maneja automáticamente fallos en llamadas a herramientas e interrupciones.</p><ul><li>Maneja automáticamente el error tool_result_missing</li><li>Corrige problemas de thinking_block_order</li><li>Configura las opciones auto_resume y session_recovery</li></ul><h3 id="_5-mecanismo-de-transformacion-de-solicitudes" tabindex="-1">5. <a href="./request-transformation/">Mecanismo de Transformación de Solicitudes</a> <a class="header-anchor" href="#_5-mecanismo-de-transformacion-de-solicitudes" aria-label="Permalink to &quot;5. [Mecanismo de Transformación de Solicitudes](./request-transformation/)&quot;">​</a></h3><p>Comprende en profundidad el mecanismo de transformación de solicitudes y cómo maneja las diferencias de protocolo entre diferentes modelos de IA.</p><ul><li>Comprende las diferencias de protocolo entre los modelos Claude y Gemini</li><li>Investiga errores 429 causados por incompatibilidad de esquemas</li><li>Optimiza la configuración de Thinking para obtener el mejor rendimiento</li></ul><h3 id="_6-guia-de-configuracion" tabindex="-1">6. <a href="./configuration-guide/">Guía de Configuración</a> <a class="header-anchor" href="#_6-guia-de-configuracion" aria-label="Permalink to &quot;6. [Guía de Configuración](./configuration-guide/)&quot;">​</a></h3><p>Domina todas las opciones de configuración para personalizar el comportamiento del plugin según tus necesidades.</p><ul><li>Ubicación y prioridad de los archivos de configuración</li><li>Configuraciones de comportamiento de modelos, rotación de cuentas y comportamiento de aplicaciones</li><li>Configuraciones recomendadas para escenarios de una cuenta, múltiples cuentas y agentes paralelos</li></ul><h3 id="_7-optimizacion-de-agentes-paralelos" tabindex="-1">7. <a href="./parallel-agents/">Optimización de Agentes Paralelos</a> <a class="header-anchor" href="#_7-optimizacion-de-agentes-paralelos" aria-label="Permalink to &quot;7. [Optimización de Agentes Paralelos](./parallel-agents/)&quot;">​</a></h3><p>Optimiza la asignación de cuentas para escenarios de agentes paralelos, habilitando el desplazamiento PID.</p><ul><li>Comprende los problemas de conflicto de cuentas en escenarios de agentes paralelos</li><li>Habilita el desplazamiento PID para que diferentes procesos prefieran cuentas diferentes</li><li>Coordina con la estrategia round-robin para maximizar la utilización de múltiples cuentas</li></ul><h3 id="_8-registros-de-depuracion" tabindex="-1">8. <a href="./debug-logging/">Registros de Depuración</a> <a class="header-anchor" href="#_8-registros-de-depuracion" aria-label="Permalink to &quot;8. [Registros de Depuración](./debug-logging/)&quot;">​</a></h3><p>Habilita los registros de depuración para investigar problemas y monitorear el estado de operación.</p><ul><li>Habilita registros de depuración para registrar información detallada</li><li>Comprende los diferentes niveles de registro y sus escenarios de aplicación</li><li>Interpreta el contenido de los registros para ubicar problemas rápidamente</li></ul><h2 id="siguientes-pasos" tabindex="-1">Siguientes Pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to &quot;Siguientes Pasos&quot;">​</a></h2><p>Después de completar el aprendizaje de funciones avanzadas, puedes:</p><ul><li>📖 Consultar las <a href="./../faq/">Preguntas Frecuentes</a> para resolver problemas encontrados durante el uso</li><li>📚 Leer el <a href="./../appendix/">Apéndice</a> para conocer el diseño de arquitectura y referencia completa de configuración</li><li>🔄 Seguir el <a href="./../changelog/">Registro de Cambios</a> para obtener las últimas funciones y cambios</li></ul>',32)])])}const g=a(r,[["render",t]]);export{m as __pageData,g as default};
